#include <iostream>
using namespace std;

class BankAccount {
private:
    int accNo;
    string name;
    double balance;

public:
    void input() {
        cout << "Enter Account Number: ";
        cin >> accNo;

        cout << "Enter Name: ";
        cin >> name;

        cout << "Enter Initial Balance: ";
        cin >> balance;
    }

    void deposit() {
        double amount;
        cout << "Enter amount to deposit: ";
        cin >> amount;

        balance += amount;
    }

    void display() {
        cout << "\n--- Account Details ---\n";
        cout << "Account No: " << accNo << endl;
        cout << "Name: " << name << endl;
        cout << "Balance: " << balance << endl;
    }
};

int main() {
    BankAccount acc;

    acc.input();     // take initial details
    acc.deposit();   // compulsory deposit
    acc.display();   // show updated balance

    return 0;
}
